#define TIMER_BASE  0xFF202000
#define HEX_BASE1 0xFF200020
#define HEX_BASE2 0xFF200030
#define COUNTER_DELAY 45000000
#define LED_BASE 0xFF200000
#define KEY_BASE 0xFF200050
#define PS2_BASE 0xFF200100

volatile int *timer_ptr = (int *)TIMER_BASE;
volatile int *hex0to3 = (int *)HEX_BASE1;
volatile int *hex4to5 = (int *)HEX_BASE2;
volatile int *led_ptr = (int *)LED_BASE;
volatile int *ps2_ptr = (int *)PS2_BASE;

volatile int pixel_buffer_start;
short int Buffer1[240][512]; // 240 rows, 512 (320 + padding) columns
short int Buffer2[240][512];
extern short int background[320][213];
extern short int start_screen[320][240];
extern const short int dollar1[10][10];
extern const short int dollar2[10][10];
extern const short int dollar5[10][10];
extern const short int digit10[10][10];
extern const short int instruction_screen[320][240];
extern const short int keyboard_screen[320][213];
extern const short int endingPage[320][240];
const short int wheelNums[38] = {35,23,4,16,33,21,6,18,31,19,8,12,29,25,10,27,37,1,13,16,24,3,15,34,22,5,17,32,20,7,11,30,26,9,28,0,2,14};
double friction;
double angleBall = 90;
double ballSpeed = 20;
int xc = 70;
int yc = 148;
int old_xc = 70;
int old_yc = 148;
int second = 30;
bool gameOn = false;
int gameNum = -1;
char gameColor = 'y';
bool restart= false;
// for keyboard
int balance = 100;
int bet[4] = {0, 0, 0, 0};
int betSum = 0;
int betChoice = -1;
char userArray[2] = {'a','a'};
// 7 seg decoder value
int hex_list[16] = {
    0b00111111, // 0
    0b00000110, // 1
    0b01011011, // 2
    0b01001111, // 3
    0b01100110, // 4
    0b01101101, // 5
    0b01111101, // 6
    0b00000111, // 7
    0b01111111, // 8
    0b01100111, // 9
    0b01110111, // A
    0b01111100, // B
    0b00111001, // C
    0b01011110, // D
    0b01111001, // E
    0b01110001  // F
};

void drawBresenhamCircle(int xc, int yc, int r, int color);
void wait_for_vsync();
void drawBackground();
void clear_screen();
void drawFilledCircle(int xc, int yc, int r, int color);
void rotateWheel();
void drawDollar();
void hex_display(int second);
void timer();
void downCounter(int *second);
void draw_start_screen();
int waitForStart();
char ps2Decoder(int scanCode);
char readKeyboard();
void processKeyInput(char key);
void displayMoney(int money);
void displayResult();
void copyChipFromBackground(int srcX, int srcY, int dstX, int dstY);
void plot_pixel(int x, int y, short int line_color);
void draw_rectangle(int x1, int y1, int x2, int y2, short int color);
void drawHighlight();
void drawExtraChips();
void draw_end_screen();
void draw_line(int x0,int y0,int x1,int y1, short int color);
void draw_key_screen();

int main(){
	volatile int * pixel_ctrl_ptr = (int *)0xFF203020;
	*pixel_ctrl_ptr = 1;
    // initialize location and direction of rectangles(not shown)
    /* set front pixel buffer to Buffer 1 */
    *(pixel_ctrl_ptr + 1) = (int) &Buffer1; // first store the address in the  back buffer
    /* now, swap the front/back buffers, to set the front buffer location */
    wait_for_vsync();
    /* initialize a pointer to the pixel buffer, used by drawing functions */
    pixel_buffer_start = *pixel_ctrl_ptr;
    clear_screen(); // pixel_buffer_start points to the pixel buffer

    /* set back pixel buffer to Buffer 2 */
    *(pixel_ctrl_ptr + 1) = (int) &Buffer2;
   	pixel_buffer_start = *(pixel_ctrl_ptr + 1); // we draw on the back buffer
    // user not pressed key0 yet
    *led_ptr = 0;
    *hex0to3 = 0;
    *hex4to5 = 0;
    int startGame = waitForStart();
	if(startGame){
        while(1){
            while(balance > 0){
                while(second > 0){
                    drawBackground();
                    drawDollar();
                    displayMoney(balance);
                    char key = ps2Decoder(readKeyboard());
                    processKeyInput(key);
                    drawExtraChips();
                    drawHighlight();
					if ((*(timer_ptr) & 0x1) == 0x1) {
                        *(timer_ptr) = 0x1;
                        downCounter(&second);
                    }
                    wait_for_vsync();
                    pixel_buffer_start = *(pixel_ctrl_ptr + 1);
                }
                downCounter(&second);
                drawFilledCircle(xc, yc, 3, 0xFFFF);
                rotateWheel();
                displayResult();
                wait_for_vsync();
                pixel_buffer_start = *(pixel_ctrl_ptr + 1);
                angleBall = 90;
                ballSpeed = 20;
                xc = 70;
                yc = 148;
                old_xc = 70;
                old_yc = 148;
                second = 30;
                gameNum = -1;
                gameColor = 'y';
                for(int i=0; i<4; i++){				
                    bet[i] = 0;
                }
                betSum = 0;
                betChoice = -1;
                userArray[0] = 'a';
                userArray[1] = 'a';
            }
            
            /* End the game when user runs out of money */
            if(balance <= 0){
                draw_end_screen();
                wait_for_vsync();
                pixel_buffer_start = *(pixel_ctrl_ptr + 1);
                char keySpace = ps2Decoder(readKeyboard());
                if(keySpace == ' '){
                    balance = 100;
                }
            }
        }
	}
	return 0;
}

/* Draw a pixel on the screen */
void plot_pixel(int x, int y, short int line_color)
{
    volatile short int *one_pixel_address;       
    one_pixel_address = (volatile short int*)(pixel_buffer_start + (y << 10) + (x << 1));
    *one_pixel_address = line_color;
}

void drawHorizontalLine(int x1, int x2, int y, int color) {
    for (int x = x1; x <= x2; x++) {
        plot_pixel(x, y, color);
    }
}

/* Draw a filled circle using the Bresenham Algorithm */
void drawFilledCircle(int xc, int yc, int r, int color) {
    int x = 0;
    int y = r;
    int d = 3 - 2 * r;

    while (x <= y) {
        // Draw horizontal lines between symmetric points on each y
        drawHorizontalLine(xc - x, xc + x, yc + y, color);
        drawHorizontalLine(xc - x, xc + x, yc - y, color);
        drawHorizontalLine(xc - y, xc + y, yc + x, color);
        drawHorizontalLine(xc - y, xc + y, yc - x, color);

        if (d < 0) {
            d = d + 4 * x + 6;
        } else {
            d = d + 4 * (x - y) + 10;
            y--;
        }
        x++;
    }
}

/* Set the entire screen to black*/
void clear_screen(){
	for(int i=0; i<320; i++){
		for(int j=0; j<240; j++){
			plot_pixel(i,j,0);
		}
	}
}

/* Swap front and back buffer */
void wait_for_vsync(){
	volatile int* pixel_ctrl_ptr = (int*) 0xff203020;
	int status;
	
	*pixel_ctrl_ptr = 1;
	
	status = *(pixel_ctrl_ptr + 3);
	
	while ((status & 0x01) != 0){
		status = *(pixel_ctrl_ptr + 3);
	}
}

void drawBackground(){
	for(int j=0; j<240; j++){
		for(int i=0; i<320; i++){
			if (j<223 && j>10){
				plot_pixel(i,j,background[i][j-10]);
			}
			else{
				plot_pixel(i,j,0x12A4);
			}
		}
	}
}

/* Draw the rotating wheel */
void rotateWheel(){
    volatile int *pixel_ctrl_ptr = (int*)0xFF203020;
	srand(time(NULL));
	friction = 0.2 + rand()/150*0.001-0.075;
	int center_x = 71;
    int center_y = 87;
    int radius = 50;
	int stopIndex = -1;
    short int wheel_area[101][101];
	float angleDev = 0.0f;
    float angle = 0.0f;
    float velocity = 10.0f;
    short int background_copy[320][213];
    for(int i = 0; i < 320; i ++){
        for(int j = 0; j < 213; j ++){
            background_copy[i][j] = background[i][j];
        }
    }
	
    while(velocity > 0){
		drawBackground();
        float theta = angle * (float)M_PI/ 180.0f;
        float cos_theta =  cosf(theta);
        float sin_theta = sinf(theta);

        for(int dx = -radius; dx <= radius; dx++){
            for(int dy = -radius; dy < radius; dy++){
                if(dx * dx + dy * dy <= radius * radius){
                    int rot_dx = (int)(dx * cos_theta + dy * sin_theta);
                    int rot_dy = (int)(-dx * sin_theta + dy * cos_theta);
                    int rotX = center_x + rot_dx;
                    int rotY = center_y + rot_dy;

                    int update_x = dx + radius;
                    int update_y = dy + radius;
                    if(rotX >= 0 && rotX < 320 && rotY >= 0 && rotY < 213){
                        wheel_area[update_x][update_y] = background_copy[rotX][rotY];
                    }
                }
            }
        }
        for(int dx = -radius; dx <= radius; dx ++){
            for(int dy = -radius; dy <= radius; dy ++){
                if(dx * dx + dy * dy <= radius * radius){
                    int x = center_x + dx;
                    int y = center_y + dy;
                    int curr_x = dx + radius;
                    int curr_y = dy + radius;
                    if(x >= 0 && x < 320 && y >= 0 && y < 213){
                        plot_pixel(x, y+10, wheel_area[curr_x][curr_y]);
                    }
                }
            }
        }
        angle += velocity;
		if (ballSpeed > 0){
			drawFilledCircle(old_xc,old_yc,3,0x6202);
			drawDollar();
			ballSpeed = ballSpeed - friction;
			angleBall = angleBall+ballSpeed;
			old_xc = xc;
			old_yc = yc;
			xc = round(71+52*cos(-angleBall*M_PI/180));
			yc = round(97+52*sin(-angleBall*M_PI/180));
			drawFilledCircle(xc, yc, 3, 0xffff);
			drawExtraChips();
			drawHighlight();
			wait_for_vsync();
			pixel_buffer_start = *(pixel_ctrl_ptr + 1);
		}
		else{
			angleDev = 360-(angleBall-(int)((angleBall-90)/360)*360-90)-(angle-(int)(angle/360)*360);
			if (angleDev < 0){
				angleDev+=360;
			}
			stopIndex = round(angleDev/360*38)+3;
			if (stopIndex >= 38){
				stopIndex = stopIndex-38;
			}
			gameNum = wheelNums[stopIndex];
			if (gameNum == 0 || gameNum == 37){
				gameColor = 'g';
			}
			else if (stopIndex %2 == 0){
				gameColor = 'b';
			}
			else{
				gameColor = 'r';
			}
			drawBackground();
			drawDollar();
			drawFilledCircle(xc, yc, 3, 0xFFFF);
			drawHighlight();
			wait_for_vsync();
			pixel_buffer_start = *(pixel_ctrl_ptr + 1);
			return;
		}
    }
}

/* Draw chips */
void drawDollar(){
	for (int i=0; i<10; i++){
		for(int j=0; j<10; j++){
			if (dollar1[i][j] != 0xffff){				
				plot_pixel(27+i,182+j,dollar1[j][i]);
			}
			if (dollar2[i][j] != 0xffff){
				plot_pixel(57+i,182+j,dollar2[j][i]);
			}
			if (dollar5[i][j] != 0xffff){
				plot_pixel(87+i,182+j,dollar5[j][i]);
			}
			if (digit10[i][j] != 0xffff){
				plot_pixel(117+i,182+j,digit10[j][i]);
			}
		}
	}
}

void draw_rectangle(int x1, int y1, int x2, int y2, short int color) {
    /* Draw top and bottom horizontal lines */
    for (int x = x1; x <= x2; x++) {
        plot_pixel(x, y1, color);
        plot_pixel(x, y2, color);
    }

    /* Draw left and right vertical lines */
    for (int y = y1 + 1; y < y2; y++) {
        plot_pixel(x1, y, color);
        plot_pixel(x2, y, color);
    }
}

/* Stack chips on top of one another */
void drawExtraChips(){
	for (int i = 1; i < bet[0]; i++) {
        int y = 182 + i * 3;
        copyChipFromBackground(20, 182, 20, y);
		for (int i=0; i<10; i++){
			for(int j=0; j<10; j++){				
				plot_pixel(27+i,y+j,dollar1[j][i]);
			}
		}
				
    }
    for (int i = 1; i < bet[1]; i++) {
        int y = 182 + i * 3;
        copyChipFromBackground(50, 182, 50, y);
		for (int i=0; i<10; i++){
			for(int j=0; j<10; j++){				
				plot_pixel(57+i,y+j,dollar2[j][i]);
			}
		}			
    }
    for (int i = 1; i < bet[2]; i++) {
        int y = 180 + i * 3;
        copyChipFromBackground(80, 182, 80, y);
		for (int i=0; i<10; i++){
			for(int j=0; j<10; j++){				
				plot_pixel(87+i,y+j,dollar5[j][i]);
			}
		}
    }
    for (int i = 1; i < bet[3]; i++) {
        int y = 180 + i * 3;
        copyChipFromBackground(110, 182, 110, y);
		for (int i=0; i<10; i++){
			for(int j=0; j<10; j++){				
				plot_pixel(117+i,y+j,digit10[j][i]);
			}
		}
    }
}

/* Draw any line */
void draw_line(int x0,int y0,int x1,int y1, short int color)
{
	bool isSteep = abs(y1-y0)>abs(x1-x0);
	if (isSteep){
		int temp = x0;
		x0 = y0;
		y0 = temp;
		temp = x1;
		x1 = y1;
		y1 = temp;
	}
	if (x0 > x1){
		int temp = x0;
		x0 = x1;
		x1 = temp;
		temp = y0;
		y0 = y1;
		y1 = temp;
	}
	int delta_x = x1-x0;
	int delta_y = abs(y1-y0);
	int error = -(delta_x/2);
	int y = y0;
	int y_step = 0;
	if (y0 < y1){
		y_step = 1;
	}else{
		y_step = -1;
	}
	
	for(int x=x0; x<=x1; x++){
		if(isSteep){
			plot_pixel(y,x,color);
		}else{
			plot_pixel(x,y,color);
		}
		error = error + delta_y;
		if (error>0){
			y = y + y_step;
			error = error - delta_x;
		}
	}
	return;
}

/* Extract the pixel values of the chips from the background image */
void copyChipFromBackground(int srcX, int srcY, int dstX, int dstY) {
    for (int dx = 0; dx < 25; dx++) {
        for (int dy = 0; dy < 25; dy++) {
            int fromX = srcX + dx;
            int fromY = srcY + dy;
            int toX = dstX + dx;
            int toY = dstY + dy;

            if (fromX >= 0 && fromX < 320 && fromY >= 10 && fromY < 223 &&
                toX >= 0 && toX < 320 && toY >= 10 && toY < 223) {
                short int color = background[fromX][fromY - 10];
                plot_pixel(toX, toY, color);
            }
        }
    }
}

void draw_start_screen(){
    for(int x = 0; x < 320; x++){
        for(int y = 0; y < 240; y++){
            plot_pixel(x, y, start_screen[x][y]);
        }
    }
}

void draw_key_screen(){
	for(int j=0; j<240; j++){
		for(int i=0; i<320; i++){
			if (j<223 && j>10){
				plot_pixel(i,j,keyboard_screen[i][j-10]);
			}
			else{
				plot_pixel(i,j,0x8C71);
			}
		}
	}
}

void draw_help_screen(){
	for(int x = 0; x < 320; x++){
		for(int y = 0; y < 240; y++){
			plot_pixel(x, y, instruction_screen[x][y]);
		}
	}
}

void draw_end_screen(){
    for(int x = 0; x < 320; x++){
        for(int y = 0; y < 240; y++){
            plot_pixel(x, y, endingPage[x][y]);
        }
    }
}

/* Pooling loop for key released */
int waitForStart(){
    volatile int *key_ptr = (int *)KEY_BASE;
    volatile int *pixel_ctrl_ptr = (int *)0xFF203020;
    // Start with Start Screen
    draw_start_screen();
    wait_for_vsync();
    pixel_buffer_start = *(pixel_ctrl_ptr + 1);  // update pointer to back buffer
    while (1) {
        int edge = *(key_ptr + 3);
        // Key1 enter the game
        if ((edge & 0x2) == 0x2) {
            *(key_ptr + 3) = edge;
            draw_help_screen();
            wait_for_vsync();
            pixel_buffer_start = *(pixel_ctrl_ptr + 1);  // now point to correct buffer
            while (1) {
                edge = *(key_ptr + 3);
                if ((edge & 0x1) == 0x1) {
                    *(key_ptr + 3) = edge;
                    draw_key_screen();
                    wait_for_vsync();
                    pixel_buffer_start = *(pixel_ctrl_ptr + 1);
                    while(1){
                        edge = *(key_ptr + 3);
                        if((edge & 0x1) == 0x1){
                            *(key_ptr + 3) = edge;
                            return 1;
                        }
                    }
                }
            }
        }
        /* KEY0 Start Game immediately from Start Screen */
        else if ((edge & 0x1) == 0x1) {
            *(key_ptr + 3) = edge; 
            return 1;
        }
    }
}

/* Showing the number on 7 segment display */
void hex_display(int second){
    int Base1Num = *hex0to3;
    Base1Num &= 0xFFFF0000;
    Base1Num |= (hex_list[second % 10]);
    Base1Num |= (hex_list[second / 10] << 8);
    *hex0to3 = Base1Num;
}

/* Display the money on the 7 segment display */
void displayMoney(int money){
    int base1 = *hex0to3;
    int base2 = 0;
    if(money > 999){
        money = 999;
    }
    base1 &= 0x0000FFFF;
    base1 |= hex_list[money % 10] << 24;
    *hex0to3 = base1;
    base2 |= hex_list[(money / 10) % 10];
    base2 |= hex_list[(money / 100) % 10] << 8;
    *hex4to5 = base2;
}

void timer(){
    volatile int *timer_ptr = (int *)0xFF202000;
    /* set timer low and high words */
    *(timer_ptr) = 0x1;
    *(timer_ptr + 2) = COUNTER_DELAY & 0xFFFF;
    *(timer_ptr + 3) = (COUNTER_DELAY >> 16) & 0xFFFF;
    *(timer_ptr + 1) = 0b0110; /*s tart the cont, and start bit of status register */
    /* poll TO bit to detect 1 sec passed */
    while((*(timer_ptr) & 0x1)== 0);
    *(timer_ptr) = 0x1;
}

void downCounter(int *second){
	hex_display(*second);
    timer();
	*led_ptr = 0;
    if(*second == 0){
        *led_ptr = 0x3FF; /* led all lights up */
        return;
    }
    if(*second > 0){
        (*second) --;
    }
    else{
        *second = 0;
    }
}

char ps2Decoder(int scanCode) {
    static bool releaseDetected = false;

    if (scanCode == 0xF0) {
        releaseDetected = true;
        return 0; /* Don't decode 0xF0 itself */
    }

    if (releaseDetected) {
        releaseDetected = false;
        switch (scanCode) {
            case 0x45: return '0';
            case 0x16: return '1';
            case 0x1E: return '2';
            case 0x26: return '3';
            case 0x25: return '4';
            case 0x2E: return '5';
            case 0x36: return '6';
            case 0x3D: return '7';
            case 0x3E: return '8';
            case 0x46: return '9';
            case 0x1C: return 'A';
            case 0x1B: return 'S';
            case 0x23: return 'D';
            case 0x2B: return 'F';
            case 0x29: return ' ';
            default: return scanCode;
        }
    }

    return 0; /* Ignore other codes unless it's after 0xF0 */
}

char readKeyboard(){
    int ps2_data = *(ps2_ptr);
    int RVALID = ps2_data & 0x8000;
    if (RVALID) {
        return ps2_data & 0xFF; /* Only return the 8-bit scan code */
    }
    return 0;
}

void processKeyInput(char key){
	if(key == 0){
		return;
	}
	else{
		if (key == 'A') {
			balance--;
			betSum++;
			bet[0] += 1;
		}
		else if (key == 'S'){
			balance -= 2;
			betSum += 2;
			bet[1] += 1;
		}
		else if (key == 'D'){
			balance = balance - 5;
			betSum += 5;
			bet[2] += 1;
		}
		else if (key == 'F'){
			balance = balance - 10;
			betSum += 10;
			bet[3] += 1;
		}
    	else if (key >= '0' && key <= '9'){
        	if(userArray[1] == 'a'){
				userArray[1] = key;
			}
			else if(userArray[0] == 'a'){
				userArray[0] = userArray[1];
				userArray[1] = key;
				if (userArray[0] == '0' && userArray[1] == '0'){
					userArray[0] = '3';
					userArray[1] = '7';
				}
			}
    	}
		else{
			if (betChoice != -1 && userArray[0] != -1 && userArray[1] != -1){
				return;
			}
			else{
				if (key == 0x05) {
    				betChoice = 0;  /* F1 */
				}
				else if (key == 0x06) {
    				betChoice = 1;  /* F2 */
				}
				else if (key == 0x04) {
    				betChoice = 2;  /* F3 */
				}
				else if (key == 0x0C) {
    				betChoice = 3;  /* F4 */
				}
				else if (key == 0x03) {
    				betChoice = 4;  /* F5 */
				}
				else if (key == 0x0B) {
    				betChoice = 5;  /* F6 */
				}
				else if (key == 0x83) {
    				betChoice = 6;  /* F7 */
				}
				else if (key == 0x0A) {
    				betChoice = 7;  /* F8 */
				}
				else if (key == 0x01) {
    				betChoice = 8;  /* F9 */
				}
				else{
					return;
				}
			}
		}
	}
}

/* Highlight a box if selected by the user */
void drawHighlight() {
    switch (betChoice) {
        case 0:
            draw_rectangle(156, 96, 205, 109, 0xFFE0);
            break;
        case 1:
            draw_rectangle(205, 96, 253, 109, 0xFFE0);
            break;
        case 2:
            draw_rectangle(253, 96, 302, 109, 0xFFE0);
            break;
        case 3:
            draw_rectangle(156, 109, 180, 122, 0xFFE0);
            break;
        case 4:
            draw_rectangle(181, 109, 205, 122, 0xFFE0);
            break;
        case 5:
            draw_rectangle(205, 109, 229, 122, 0xFFE0);
            break;
        case 6:
            draw_rectangle(229, 109, 253, 122, 0xFFE0);
            break;
		case 7:
			draw_rectangle(253, 109, 277, 122, 0xFFE0);
			break;
		case 8:
			draw_rectangle(277, 109, 302, 122, 0xFFE0);
			break;
		case -1:
			int userNum= -1;
			if (userArray[0] == 'a' && userArray[1] == 'a'){
				break;
			}
			if (userArray[0] != 'a'){
				userNum = (userArray[0]-'0')*10 + userArray[1]-'0';
			}
			else{
				userNum = userArray[1]-'0';
			}
			if (userNum != 0 && userNum != 37 && userNum != -1){
				int dx = round((userNum-1)/3*12.1);
				int dy = round(-(userNum-1)%3*17.4);
				draw_rectangle(156+dx, 79+dy, 168+dx, 96+dy, 0xFFE0);
			}
			else if (userNum == 0){
				draw_line(137,88,140,104,0xFFE0);
				draw_line(137,88,140,74,0xFFE0);
				draw_line(140,104,156,104,0xFFE0);
				draw_line(140,74,156,74,0xFFE0);
				draw_line(156,74,156,104,0xFFE0);
			}
			else if (userNum == 37){
				draw_line(137,65,140,74,0xFFE0);
				draw_line(137,65,143,44,0xFFE0);
				draw_line(143,74,156,74,0xFFE0);
				draw_line(143,44,156,44,0xFFE0);
				draw_line(156,44,156,74,0xFFE0);
			}
			break;
        default:
            break;
    }
}

/* Display the winning number and calculate user balance */
void displayResult(){
	int userNum= -1;
	if (userArray[0] != 'a'){
		userNum = (userArray[0]-'0')*10 + userArray[1]-'0';
	}
	else{
		userNum = userArray[1]-'0';
	}
	if (betChoice == -1 && gameNum == userNum){
		balance += betSum*36;
	}
	else if (betChoice == 0 && gameNum <= 12 && gameNum >= 1){
		balance += betSum*3;
	}
	else if (betChoice == 1 && gameNum <= 24 && gameNum >= 13){
		balance += betSum*3;
	}
	else if (betChoice == 2 && gameNum <= 36 && gameNum >= 25){
		balance += betSum*3;
	}
	else if (betChoice == 3 && gameNum <= 18 && gameNum >= 1){
		balance += betSum*2;
	}
	else if (betChoice == 4 && gameNum % 2 == 0){
		balance += betSum*2;
	}
	else if (betChoice == 5 && gameColor == 'r'){
		balance += betSum*2;
	}
	else if (betChoice == 6 && gameColor == 'b'){
		balance += betSum*2;
	}
	else if (betChoice == 7 && gameNum % 2 == 1){
		balance += betSum*2;
	}
	else if (betChoice == 8 && gameNum <= 36 && gameNum >= 19){
		balance += betSum*2;
	}
	displayMoney(balance);
}

